<script setup>import {onMounted,ref} from 'vue';import {getMyTradeIns} from '../api/tradeInApi';const list=ref([]),loading=ref(true),error=ref('');const labels={SUBMITTED:'已送出',INSPECTING:'檢測中',QUOTED:'已報價',ACCEPTED:'已接受',REJECTED:'已拒絕',COMPLETED:'已完成',CANCELLED:'已取消'};onMounted(async()=>{try{list.value=await getMyTradeIns()}catch(e){error.value=e.message}finally{loading.value=false}})</script>
<template><section class="member-section"><div class="page-heading"><div><span class="eyebrow">MY TRADE-INS</span><h1>我的收購</h1><p>查看估價申請與報價處理進度。</p></div><RouterLink class="button button-primary" to="/trade-in">新增估價申請</RouterLink></div><p v-if="error" class="alert alert-error">{{error}}</p><div v-if="loading" class="loading-state">正在載入收購紀錄…</div><div v-else-if="!list.length" class="empty-state"><h2>目前沒有估價申請</h2><RouterLink class="button button-primary" to="/trade-in">開始估價</RouterLink></div><div v-else class="record-grid"><RouterLink v-for="item in list" :key="item.id" class="record-card card" :to="`/member/trade-ins/${item.id}`"><span class="badge">{{labels[item.status]||item.status}}</span><h2>{{item.brand}} {{item.model}}</h2><p>{{item.tradeInNumber}}</p><strong v-if="item.quotedPrice">報價 NT$ {{Number(item.quotedPrice).toLocaleString()}}</strong><small>{{new Date(item.createdAt).toLocaleString('zh-TW')}}</small></RouterLink></div></section></template>
